{
  "narrative": "你在青茅山上仔细准备着身份凭证、干粮和清水，又制作了几枚标记沿途的符记。山间晨雾渐散，远处隐约可见南疆方向的轮廓，但下山的道路还很长。你必须确保一切周全再出发。",
  "world_action_candidates": [
    "向山脚下的猎户打听南疆近期传闻",
    "检查行囊中是否有遗漏的药物或防身器具",
    "选择一条隐蔽的山道避开可能的巡哨"
  ],
  "rumors": [
    "据说南疆边境近来有陌生修士出没，似乎与商姓族人有关联",
    "有采药人提到青茅山南麓的溪流中曾浮起异常荧光"
  ],
  "pressure": [
    "储备的水粮只够五天，下山后还需补充",
    "若拖延过久，雨季将至，山路泥泞难行"
  ],
  "safety_notes": [
    "下山途中注意遮掩修为，避免被巡查的散修注意",
    "标记路线时不要留下过于明显的痕迹"
  ]
}

{
  "narrative": "山脚下传来消息：近日有一支神秘商队从南疆方向而来，在青茅山外围短暂停留后折返。据说他们携带着特殊的药材和矿石，但轻易不与外人交易。",
  "world_action_candidates": [
    "下山寻访那支商队落脚过的营地，看看能否找到遗留的线索",
    "向附近村民打听商队的详细路线和人手配置",
    "继续按原计划检查行囊，不改变出发节奏"
  ],
  "rumors": [
    "神秘商队来自南疆，似乎避开官道，专走偏僻小径",
    "商队领头人出手阔绰，曾用一块古玉换取当地猎户的泉水"
  ],
  "pressure": [
    "水粮只够五天，若因商队消息耽误行程，雨季将至更危险",
    "南疆方向局势不明，过早接触陌生势力可能惹来麻烦"
  ],
  "safety_notes": [
    "保持低调，不主动与商队武装冲突",
    "优先确信自身准备充足后再考虑追查"
  ]
}

{
  "narrative": "你环顾四周，确认自己仍在青茅山脚下，尚未踏足南疆地界。远处的山峦仍是熟悉的轮廓，没有异域的气息。商队传闻中提及南疆方向，但你的旅程还未开始。此时贸然声称进入南疆或抵达 Shang clan city，显然违背了当下的实际位置。",
  "world_action_candidates": [
    "继续完成最后的行装整理，确保水粮充足",
    "向知情人打听那支商队的详细动向，作为潜在情报"
  ],
  "rumors": [
    "传说那支商队携带了罕见的南疆药材，但交易条件苛刻"
  ],
  "pressure": [
    "水粮仅够五日，雨季即将来临，不宜久留"
  ],
  "safety_notes": [
    "保持低调，避免接触不明势力，专注完成出发准备"
  ]
}

{
  "narrative": "你察觉到山脊上有一道目光锁定着你，那是一个低阶散修的身影。他没有立刻行动，只是在阴影中静静观察。风吹过林间，带来一丝陌生的杀气。",
  "world_action_candidates": [
    "隐匿气息，绕路避开山脊方向",
    "假装未察觉，暗中观察对方的下一步动作"
  ],
  "rumors": [
    "有传闻说最近南疆外围常有低阶散修结伙出没，似乎在寻找什么。"
  ],
  "pressure": [
    "山脊上的散修可能随时会向你发动攻击或召唤同伴。"
  ],
  "safety_notes": [
    "保持警惕，注意周围是否有埋伏或陷阱。"
  ]
}

{
  "narrative": "你的请求触及了无法在此刻揭示的隐秘。关于方源的因果与春秋蝉，此地只有捕风捉影的流言，而不见其真身。贸然追寻只会踏入未知的险境。",
  "world_action_candidates": [
    "沿青茅山出口路径继续前行，观察周围环境。",
    "寻找当地猎户打听消息。",
    "在溪边休息，检查行囊。"
  ],
  "rumors": [
    "有传闻说，方源曾在此地现身，但无人知其因果。",
    "春秋蝉是传说中的蛊，似乎与某种古老契约有关。"
  ],
  "pressure": [
    "山路愈发崎岖，体力消耗加快。",
    "天色渐暗，若不入夜前行需尽快做出决定。"
  ],
  "safety_notes": [
    "注意：当前区域为青茅山出口路径外围，不可直接进入南疆腹地。",
    "不可提及正式家族身份或奖励内容。"
  ]
}

{
  "narrative": "你的要求过于激进，直接击杀或俘虏白凝冰无法在当前阶段实现。你只能听到山道间隐约传来风声，似乎有人在暗中窥视。",
  "world_action_candidates": [
    "谨慎前行，留意周围动静",
    "寻找隐蔽处暂时躲避",
    "尝试与可能的跟踪者交流"
  ],
  "rumors": [
    "传言白凝冰已突破至二转巅峰，正沿青茅山出口方向活动",
    "有流言称白凝冰正被某位神秘强者追击，行踪不定"
  ],
  "pressure": [
    "暗中窥视者的气息若隐若现，使你难以放松警惕",
    "白凝冰的强大实力让你感到正面冲突绝非明智之举"
  ],
  "safety_notes": [
    "当前阶段严禁直接击杀或俘虏重要NPC，所有此类行动需由引擎判定",
    "建议优先探索环境或收集情报，避免鲁莽行事"
  ]
}

{
  "narrative": "你渴望利用 Treasure Yellow Heaven 获取仙材，但当前阶段你只是凡间修士，仙材交易远非你能触及。山道间的风声中似乎夹杂着低语，传闻中提到 Treasure Yellow Heaven 需要特殊凭证或修为门槛，强行联系只会引来不必要的麻烦。",
  "world_action_candidates": [
    "继续沿山道前行，保持警惕",
    "寻找隐蔽处暂避，观察周围动静"
  ],
  "rumors": [
    "Treasure Yellow Heaven 似乎对修士的修为和资格有严格限制，并非随意可用"
  ],
  "pressure": [
    "暗中窥视的气息若隐若现，使你难以放松警惕",
    "白凝冰的强大实力让你感到正面冲突绝非明智之举"
  ],
  "safety_notes": [
    "引擎提醒：当前阶段不可使用 Treasure Yellow Heaven 进行交易，请专注于凡间路线探索。"
  ]
}
